    32â†’#include "server.h"
    33â†’#include "pqsort.h" /* Partial qsort for SORT+LIMIT */
    34â†’#include <math.h> /* isnan() */
    35â†’
    36â†’zskiplistNode* zslGetElementByRank(zskiplist *zsl, unsigned long rank);
    37â†’
    38â†’redisSortOperation *createSortOperation(int type, robj *pattern) {
    39â†’    redisSortOperation *so = zmalloc(sizeof(*so));
    40â†’    so->type = type;
    41â†’    so->pattern = pattern;
    42â†’    return so;
    43â†’}
    44â†’
    45â†’/* Return the value associated to the key with a name obtained using
    46â†’ * the following rules:
    47â†’ *
    48â†’ * 1) The first occurrence of '*' in 'pattern' is substituted with 'subst'.
    49â†’ *
    50â†’ * 2) If 'pattern' matches the "->" string, everything on the left of
    51â†’ *    the arrow is treated as the name of a hash field, and the part on the
    52â†’ *    left as the key name containing a hash. The value of the specified
    53â†’ *    field is returned.
    54â†’ *
    55â†’ * 3) If 'pattern' equals "#", the function simply returns 'subst' itself so
    56â†’ *    that the SORT command can be used like: SORT key GET # to retrieve
    57â†’ *    the Set/List elements directly.
    58â†’ *
    59â†’ * The returned object will always have its refcount increased by 1
    60â†’ * when it is non-NULL. */
    61â†’robj *lookupKeyByPattern(redisDb *db, robj *pattern, robj *subst) {
    62â†’    char *p, *f, *k;
    63â†’    sds spat, ssub;
    64â†’    robj *keyobj, *fieldobj = NULL, *o;
    65â†’    int prefixlen, sublen, postfixlen, fieldlen;
    66â†’
    67â†’    /* If the pattern is "#" return the substitution object itself in order
    68â†’     * to implement the "SORT ... GET #" feature. */
    69â†’    spat = pattern->ptr;
    70â†’    if (spat[0] == '#' && spat[1] == '\0') {
    71â†’        incrRefCount(subst);
    72â†’        return subst;
    73â†’    }
    74â†’
    75â†’    /* The substitution object may be specially encoded. If so we create
    76â†’     * a decoded object on the fly. Otherwise getDecodedObject will just
    77â†’     * increment the ref count, that we'll decrement later. */
    78â†’    subst = getDecodedObject(subst);
    79â†’    ssub = subst->ptr;
    80â†’
    81â†’    /* If we can't find '*' in the pattern we return NULL as to GET a
    82â†’     * fixed key does not make sense. */
    83â†’    p = strchr(spat,'*');
    84â†’    if (!p) {
    85â†’        decrRefCount(subst);
    86â†’        return NULL;
    87â†’    }
    88â†’
    89â†’    /* Find out if we're dealing with a hash dereference. */
    90â†’    if ((f = strstr(p+1, "->")) != NULL && *(f+2) != '\0') {
    91â†’        fieldlen = sdslen(spat)-(f-spat)-2;
    92â†’        fieldobj = createStringObject(f+2,fieldlen);
    93â†’    } else {
    94â†’        fieldlen = 0;
    95â†’    }
    96â†’
    97â†’    /* Perform the '*' substitution. */
    98â†’    prefixlen = p-spat;
    99â†’    sublen = sdslen(ssub);
   100â†’    postfixlen = sdslen(spat)-(prefixlen+1)-(fieldlen ? fieldlen+2 : 0);
   101â†’    keyobj = createStringObject(NULL,prefixlen+sublen+postfixlen);
   102â†’    k = keyobj->ptr;
   103â†’    memcpy(k,spat,prefixlen);
   104â†’    memcpy(k+prefixlen,ssub,sublen);
   105â†’    memcpy(k+prefixlen+sublen,p+1,postfixlen);
   106â†’    decrRefCount(subst); /* Incremented by decodeObject() */
   107â†’
   108â†’    /* Lookup substituted key */
   109â†’    o = lookupKeyRead(db,keyobj);
   110â†’    if (o == NULL) goto noobj;
   111â†’
   112â†’    if (fieldobj) {
   113â†’        if (o->type != OBJ_HASH) goto noobj;
   114â†’
   115â†’        /* Retrieve value from hash by the field name. The returend object
   116â†’         * is a new object with refcount already incremented. */
   117â†’        o = hashTypeGetValueObject(o, fieldobj->ptr);
   118â†’    } else {
   119â†’        if (o->type != OBJ_STRING) goto noobj;
   120â†’
   121â†’        /* Every object that this function returns needs to have its refcount
   122â†’         * increased. sortCommand decreases it again. */
   123â†’        incrRefCount(o);
   124â†’    }
   125â†’    decrRefCount(keyobj);
   126â†’    if (fieldobj) decrRefCount(fieldobj);
   127â†’    return o;
   128â†’
   129â†’noobj:
   130â†’    decrRefCount(keyobj);
   131â†’    if (fieldlen) decrRefCount(fieldobj);
   132â†’    return NULL;
   133â†’}
   134â†’
   135â†’/* sortCompare() is used by qsort in sortCommand(). Given that qsort_r with
   136â†’ * the additional parameter is not standard but a BSD-specific we have to
   137â†’ * pass sorting parameters via the global 'server' structure */
   138â†’int sortCompare(const void *s1, const void *s2) {
   139â†’    const redisSortObject *so1 = s1, *so2 = s2;
   140â†’    int cmp;
   141â†’
   142â†’    if (!server.sort_alpha) {
   143â†’        /* Numeric sorting. Here it's trivial as we precomputed scores */
   144â†’        if (so1->u.score > so2->u.score) {
   145â†’            cmp = 1;
   146â†’        } else if (so1->u.score < so2->u.score) {
   147â†’            cmp = -1;
   148â†’        } else {
   149â†’            /* Objects have the same score, but we don't want the comparison
   150â†’             * to be undefined, so we compare objects lexicographically.
   151â†’             * This way the result of SORT is deterministic. */
   152â†’            cmp = compareStringObjects(so1->obj,so2->obj);
   153â†’        }
   154â†’    } else {
   155â†’        /* Alphanumeric sorting */
   156â†’        if (server.sort_bypattern) {
   157â†’            if (!so1->u.cmpobj || !so2->u.cmpobj) {
   158â†’                /* At least one compare object is NULL */
   159â†’                if (so1->u.cmpobj == so2->u.cmpobj)
   160â†’                    cmp = 0;
   161â†’                else if (so1->u.cmpobj == NULL)
   162â†’                    cmp = -1;
   163â†’                else
   164â†’                    cmp = 1;
   165â†’            } else {
   166â†’                /* We have both the objects, compare them. */
   167â†’                if (server.sort_store) {
   168â†’                    cmp = compareStringObjects(so1->u.cmpobj,so2->u.cmpobj);
   169â†’                } else {
   170â†’                    /* Here we can use strcoll() directly as we are sure that
   171â†’                     * the objects are decoded string objects. */
   172â†’                    cmp = strcoll(so1->u.cmpobj->ptr,so2->u.cmpobj->ptr);
   173â†’                }
   174â†’            }
   175â†’        } else {
   176â†’            /* Compare elements directly. */
   177â†’            if (server.sort_store) {
   178â†’                cmp = compareStringObjects(so1->obj,so2->obj);
   179â†’            } else {
   180â†’                cmp = collateStringObjects(so1->obj,so2->obj);
   181â†’            }
   182â†’        }
   183â†’    }
   184â†’    return server.sort_desc ? -cmp : cmp;
   185â†’}
   186â†’
   187â†’/* The SORT command is the most complex command in Redis. Warning: this code
   188â†’ * is optimized for speed and a bit less for readability */
   189â†’void sortCommand(client *c) {
   190â†’    list *operations;
   191â†’    unsigned int outputlen = 0;
   192â†’    int desc = 0, alpha = 0;
   193â†’    long limit_start = 0, limit_count = -1, start, end;
   194â†’    int j, dontsort = 0, vectorlen;
   195â†’    int getop = 0; /* GET operation counter */
   196â†’    int int_conversion_error = 0;
   197â†’    int syntax_error = 0;
   198â†’    robj *sortval, *sortby = NULL, *storekey = NULL;
   199â†’    redisSortObject *vector; /* Resulting vector to sort */
   200â†’
   201â†’    /* Lookup the key to sort. It must be of the right types */
   202â†’    sortval = lookupKeyRead(c->db,c->argv[1]);
   203â†’    if (sortval && sortval->type != OBJ_SET &&
   204â†’                   sortval->type != OBJ_LIST &&
   205â†’                   sortval->type != OBJ_ZSET)
   206â†’    {
   207â†’        addReply(c,shared.wrongtypeerr);
   208â†’        return;
   209â†’    }
   210â†’
   211â†’    /* Create a list of operations to perform for every sorted element.
   212â†’     * Operations can be GET */
   213â†’    operations = listCreate();
   214â†’    listSetFreeMethod(operations,zfree);
   215â†’    j = 2; /* options start at argv[2] */
   216â†’
   217â†’    /* Now we need to protect sortval incrementing its count, in the future
   218â†’     * SORT may have options able to overwrite/delete keys during the sorting
   219â†’     * and the sorted key itself may get destroyed */
   220â†’    if (sortval)
   221â†’        incrRefCount(sortval);
   222â†’    else
   223â†’        sortval = createQuicklistObject();
   224â†’
   225â†’    /* The SORT command has an SQL-alike syntax, parse it */
   226â†’    while(j < c->argc) {
   227â†’        int leftargs = c->argc-j-1;
   228â†’        if (!strcasecmp(c->argv[j]->ptr,"asc")) {
   229â†’            desc = 0;
   230â†’        } else if (!strcasecmp(c->argv[j]->ptr,"desc")) {
   231â†’            desc = 1;
   232â†’        } else if (!strcasecmp(c->argv[j]->ptr,"alpha")) {
   233â†’            alpha = 1;
   234â†’        } else if (!strcasecmp(c->argv[j]->ptr,"limit") && leftargs >= 2) {
   235â†’            if ((getLongFromObjectOrReply(c, c->argv[j+1], &limit_start, NULL)
   236â†’                 != C_OK) ||
   237â†’                (getLongFromObjectOrReply(c, c->argv[j+2], &limit_count, NULL)
   238â†’                 != C_OK))
   239â†’            {
   240â†’                syntax_error++;
   241â†’                break;
   242â†’            }
   243â†’            j+=2;
   244â†’        } else if (!strcasecmp(c->argv[j]->ptr,"store") && leftargs >= 1) {
   245â†’            storekey = c->argv[j+1];
   246â†’            j++;
   247â†’        } else if (!strcasecmp(c->argv[j]->ptr,"by") && leftargs >= 1) {
   248â†’            sortby = c->argv[j+1];
   249â†’            /* If the BY pattern does not contain '*', i.e. it is constant,
   250â†’             * we don't need to sort nor to lookup the weight keys. */
   251â†’            if (strchr(c->argv[j+1]->ptr,'*') == NULL) {
   252â†’                dontsort = 1;
   253â†’            } else {
   254â†’                /* If BY is specified with a real patter, we can't accept
   255â†’                 * it in cluster mode. */
   256â†’                if (server.cluster_enabled) {
   257â†’                    addReplyError(c,"BY option of SORT denied in Cluster mode.");
   258â†’                    syntax_error++;
   259â†’                    break;
   260â†’                }
   261â†’            }
   262â†’            j++;
   263â†’        } else if (!strcasecmp(c->argv[j]->ptr,"get") && leftargs >= 1) {
   264â†’            if (server.cluster_enabled) {
   265â†’                addReplyError(c,"GET option of SORT denied in Cluster mode.");
   266â†’                syntax_error++;
   267â†’                break;
   268â†’            }
   269â†’            listAddNodeTail(operations,createSortOperation(
   270â†’                SORT_OP_GET,c->argv[j+1]));
   271â†’            getop++;
   272â†’            j++;
   273â†’        } else {
   274â†’            addReply(c,shared.syntaxerr);
   275â†’            syntax_error++;
   276â†’            break;
   277â†’        }
   278â†’        j++;
   279â†’    }
   280â†’
   281â†’    /* Handle syntax errors set during options parsing. */
   282â†’    if (syntax_error) {
   283â†’        decrRefCount(sortval);
   284â†’        listRelease(operations);
   285â†’        return;
   286â†’    }
   287â†’
   288â†’    /* When sorting a set with no sort specified, we must sort the output
   289â†’     * so the result is consistent across scripting and replication.
   290â†’     *
   291â†’     * The other types (list, sorted set) will retain their native order
   292â†’     * even if no sort order is requested, so they remain stable across
   293â†’     * scripting and replication. */
   294â†’    if (dontsort &&
   295â†’        sortval->type == OBJ_SET &&
   296â†’        (storekey || c->flags & CLIENT_LUA))
   297â†’    {
   298â†’        /* Force ALPHA sorting */
   299â†’        dontsort = 0;
   300â†’        alpha = 1;
   301â†’        sortby = NULL;
   302â†’    }
   303â†’
   304â†’    /* Destructively convert encoded sorted sets for SORT. */
   305â†’    if (sortval->type == OBJ_ZSET)
   306â†’        zsetConvert(sortval, OBJ_ENCODING_SKIPLIST);
   307â†’
   308â†’    /* Objtain the length of the object to sort. */
   309â†’    switch(sortval->type) {
   310â†’    case OBJ_LIST: vectorlen = listTypeLength(sortval); break;
   311â†’    case OBJ_SET: vectorlen =  setTypeSize(sortval); break;
   312â†’    case OBJ_ZSET: vectorlen = dictSize(((zset*)sortval->ptr)->dict); break;
   313â†’    default: vectorlen = 0; serverPanic("Bad SORT type"); /* Avoid GCC warning */
   314â†’    }
   315â†’
   316â†’    /* Perform LIMIT start,count sanity checking. */
   317â†’    start = (limit_start < 0) ? 0 : limit_start;
   318â†’    end = (limit_count < 0) ? vectorlen-1 : start+limit_count-1;
   319â†’    if (start >= vectorlen) {
   320â†’        start = vectorlen-1;
   321â†’        end = vectorlen-2;
   322â†’    }
   323â†’    if (end >= vectorlen) end = vectorlen-1;
   324â†’
   325â†’    /* Whenever possible, we load elements into the output array in a more
   326â†’     * direct way. This is possible if:
   327â†’     *
   328â†’     * 1) The object to sort is a sorted set or a list (internally sorted).
   329â†’     * 2) There is nothing to sort as dontsort is true (BY <constant string>).
   330â†’     *
   331â†’     * In this special case, if we have a LIMIT option that actually reduces
   332â†’     * the number of elements to fetch, we also optimize to just load the
   333â†’     * range we are interested in and allocating a vector that is big enough
   334â†’     * for the selected range length. */
   335â†’    if ((sortval->type == OBJ_ZSET || sortval->type == OBJ_LIST) &&
   336â†’        dontsort &&
   337â†’        (start != 0 || end != vectorlen-1))
   338â†’    {
   339â†’        vectorlen = end-start+1;
   340â†’    }
   341â†’
   342â†’    /* Load the sorting vector with all the objects to sort */
   343â†’    vector = zmalloc(sizeof(redisSortObject)*vectorlen);
   344â†’    j = 0;
   345â†’
   346â†’    if (sortval->type == OBJ_LIST && dontsort) {
   347â†’        /* Special handling for a list, if 'dontsort' is true.
   348â†’         * This makes sure we return elements in the list original
   349â†’         * ordering, accordingly to DESC / ASC options.
   350â†’         *
   351â†’         * Note that in this case we also handle LIMIT here in a direct
   352â†’         * way, just getting the required range, as an optimization. */
   353â†’        if (end >= start) {
   354â†’            listTypeIterator *li;
   355â†’            listTypeEntry entry;
   356â†’            li = listTypeInitIterator(sortval,
   357â†’                    desc ? (long)(listTypeLength(sortval) - start - 1) : start,
   358â†’                    desc ? LIST_HEAD : LIST_TAIL);
   359â†’
   360â†’            while(j < vectorlen && listTypeNext(li,&entry)) {
   361â†’                vector[j].obj = listTypeGet(&entry);
   362â†’                vector[j].u.score = 0;
   363â†’                vector[j].u.cmpobj = NULL;
   364â†’                j++;
   365â†’            }
   366â†’            listTypeReleaseIterator(li);
   367â†’            /* Fix start/end: output code is not aware of this optimization. */
   368â†’            end -= start;
   369â†’            start = 0;
   370â†’        }
   371â†’    } else if (sortval->type == OBJ_LIST) {
   372â†’        listTypeIterator *li = listTypeInitIterator(sortval,0,LIST_TAIL);
   373â†’        listTypeEntry entry;
   374â†’        while(listTypeNext(li,&entry)) {
   375â†’            vector[j].obj = listTypeGet(&entry);
   376â†’            vector[j].u.score = 0;
   377â†’            vector[j].u.cmpobj = NULL;
   378â†’            j++;
   379â†’        }
   380â†’        listTypeReleaseIterator(li);
   381â†’    } else if (sortval->type == OBJ_SET) {
   382â†’        setTypeIterator *si = setTypeInitIterator(sortval);
   383â†’        sds sdsele;
   384â†’        while((sdsele = setTypeNextObject(si)) != NULL) {
   385â†’            vector[j].obj = createObject(OBJ_STRING,sdsele);
   386â†’            vector[j].u.score = 0;
   387â†’            vector[j].u.cmpobj = NULL;
   388â†’            j++;
   389â†’        }
   390â†’        setTypeReleaseIterator(si);
   391â†’    } else if (sortval->type == OBJ_ZSET && dontsort) {
   392â†’        /* Special handling for a sorted set, if 'dontsort' is true.
   393â†’         * This makes sure we return elements in the sorted set original
   394â†’         * ordering, accordingly to DESC / ASC options.
   395â†’         *
   396â†’         * Note that in this case we also handle LIMIT here in a direct
   397â†’         * way, just getting the required range, as an optimization. */
   398â†’
   399â†’        zset *zs = sortval->ptr;
   400â†’        zskiplist *zsl = zs->zsl;
   401â†’        zskiplistNode *ln;
   402â†’        sds sdsele;
   403â†’        int rangelen = vectorlen;
   404â†’
   405â†’        /* Check if starting point is trivial, before doing log(N) lookup. */
   406â†’        if (desc) {
   407â†’            long zsetlen = dictSize(((zset*)sortval->ptr)->dict);
   408â†’
   409â†’            ln = zsl->tail;
   410â†’            if (start > 0)
   411â†’                ln = zslGetElementByRank(zsl,zsetlen-start);
   412â†’        } else {
   413â†’            ln = zsl->header->level[0].forward;
   414â†’            if (start > 0)
   415â†’                ln = zslGetElementByRank(zsl,start+1);
   416â†’        }
   417â†’
   418â†’        while(rangelen--) {
   419â†’            serverAssertWithInfo(c,sortval,ln != NULL);
   420â†’            sdsele = ln->ele;
   421â†’            vector[j].obj = createStringObject(sdsele,sdslen(sdsele));
   422â†’            vector[j].u.score = 0;
   423â†’            vector[j].u.cmpobj = NULL;
   424â†’            j++;
   425â†’            ln = desc ? ln->backward : ln->level[0].forward;
   426â†’        }
   427â†’        /* Fix start/end: output code is not aware of this optimization. */
   428â†’        end -= start;
   429â†’        start = 0;
   430â†’    } else if (sortval->type == OBJ_ZSET) {
   431â†’        dict *set = ((zset*)sortval->ptr)->dict;
   432â†’        dictIterator *di;
   433â†’        dictEntry *setele;
   434â†’        sds sdsele;
   435â†’        di = dictGetIterator(set);
